    @PostMapping("/auth/login")
    ApiResponse<Map<String,Object>> login(@RequestBody Map<String,String> body) {
        AuthService.LoginResult result=authService.login(body.get("username"),body.get("password"));PlatformUser user=result.user();
        Map<String,Object> response=new LinkedHashMap<>();response.put("token",result.token());response.put("user",user.getUsername());response.put("name",user.getName());response.put("role",user.getRole());response.put("companyIds",user.getCompanyIds());response.put("allProjectCompanyIds",user.getAllProjectCompanyIds());response.put("projectIds",user.getProjectIds());response.put("companyModules",moduleMap(user.getCompanyRoleIds()));response.put("projectModules",moduleMap(user.getProjectRoleIds()));
        return ApiResponse.ok(response);
    }
    @PostMapping("/auth/logout") ApiResponse<Void> logout(jakarta.servlet.http.HttpServletRequest req){authService.logout(req);return ApiResponse.ok(null);}

    @PostMapping("/h5/worker-entry/login")
    ApiResponse<Map<String,Object>> h5Login(@RequestBody Map<String,String> body) {
        String username=text(body.get("username")),password=text(body.get("password"));
        Optional<PlatformUser> platformAccount=platformUsers.findByPhone(username).or(()->platformUsers.findByUsername(username));
        if(platformAccount.isPresent()) {
            try {
                AuthService.LoginResult login=authService.login(username,password);
                List<Project> managed=visibleProjects(login.scope()).stream().filter(p->isProjectManager(login.scope(),p.getId())).toList();
                if(!managed.isEmpty())return ApiResponse.ok(Map.of("token",login.token(),"actorType","PROJECT_MANAGER","name",login.user().getName(),"projects",managed));
            } catch(BusinessException ignored) {
                // The same phone can be both a platform account and a worker team leader.
            }
        }
        Worker leader=workers.findAll().stream().filter(w->Boolean.TRUE.equals(w.getTeamLeader())&&username.equals(w.getPhone())&&authService.verify(password,w.getTeamLeaderPassword())).findFirst().orElseThrow(()->new BusinessException("账号或密码错误，或当前人员不是班组长"));
        String token=UUID.randomUUID().toString();h5Sessions.put(token,new H5Actor("TEAM_LEADER",leader.getId(),Set.of(leader.getProjectId()),leader.getTeamId()));
        return ApiResponse.ok(Map.of("token",token,"actorType","TEAM_LEADER","name",leader.getName(),"projects",List.of(require(projects,leader.getProjectId(),"项目不存在"))));
    }
    @GetMapping("/h5/worker-entry/options")
    ApiResponse<Map<String,Object>> h5Options(jakarta.servlet.http.HttpServletRequest req){
        H5Actor actor=h5Actor(req);List<Project> ps=projects.findAllById(actor.projectIds());List<Team> ts="TEAM_LEADER".equals(actor.type())?List.of(require(teams,actor.teamId(),"班组不存在")):ps.stream().flatMap(p->teams.findByProjectId(p.getId()).stream()).toList();
        return ApiResponse.ok(Map.of("actorType",actor.type(),"projects",ps,"teams",ts,"workTypes",workTypes.findAllByOrderBySortOrderAscIdAsc()));
    }
    @PostMapping("/h5/worker-entry/id-card-ocr")
    ApiResponse<Map<String,Object>> h5IdCardOcr(jakarta.servlet.http.HttpServletRequest req,@RequestBody(required=false) Map<String,Object> body){h5Actor(req);return ApiResponse.ok(Map.of("name","待核验人员","idCardNo","330681199001011234","gender","男","nation","汉","birthDate","1990-01-01","address","身份证照片模拟识别地址"));}
    @PostMapping("/h5/worker-entry/workers")
    ApiResponse<Map<String,Object>> h5AddWorker(jakarta.servlet.http.HttpServletRequest req,@RequestBody Worker v){
        H5Actor actor=h5Actor(req);if(!actor.projectIds().contains(v.getProjectId()))throw new BusinessException("无权向该项目新增人员");
        Team team=require(teams,"TEAM_LEADER".equals(actor.type())?actor.teamId():v.getTeamId(),"请选择班组");if(!Objects.equals(team.getProjectId(),v.getProjectId()))throw new BusinessException("班组不属于所选项目");
        v.setTeamId(team.getId());v.setParticipantUnitId(team.getParticipantUnitId());v.setStatus("ON_SITE");v.setEntryDate(LocalDate.now().toString());validateWorker(v,null);v.setPersonCode(nextWorkerCode(v.getProjectId()));v.setQrToken(UUID.randomUUID().toString().replace("-",""));v.setWorkerType("劳务工人");v.setSafetyEducationStatus("FAILED");v.setAccessStatus("ACCESS_DISABLED");v.setDeviceSyncStatus("PENDING_SYNC");v.setRealNameReportStatus("NOT_SUBMITTED");Worker saved=workers.save(v);
        for(ProjectArea area:areas.findByProjectId(v.getProjectId()))if("ACTIVE".equals(area.getStatus()))permissions.save(WorkerAreaPermission.builder().workerId(saved.getId()).projectId(saved.getProjectId()).areaId(area.getId()).permissionStatus("ACTIVE").deviceSyncStatus("PENDING_SYNC").build());
        String syncMessage;try{accessService.syncWorker(saved.getId());syncMessage="人员已自动下发到对应区域设备";}catch(BusinessException e){syncMessage="人员档案已创建，设备等待下发："+e.getMessage();}
        return ApiResponse.ok(Map.of("worker",saved,"syncMessage",syncMessage));
    }

