    @GetMapping("/platform/overview") ApiResponse<Map<String,Object>> platformOverview(jakarta.servlet.http.HttpServletRequest req){requireSuperAdmin(req);long accountCount=platformUsers.findAll().stream().filter(u->Set.of("SUPER_ADMIN","COMPANY_ADMIN").contains(u.getRole())).count();return ApiResponse.ok(Map.of("companyCount",companies.count(),"projectCount",projects.count(),"workerCount",workers.count(),"accountCount",accountCount)); }
    @GetMapping("/dashboard") ApiResponse<Map<String,Object>> dashboard(jakarta.servlet.http.HttpServletRequest req,@RequestParam(required=false) Long projectId){if(projectId==null)requireSuperAdmin(req);else checkProject(auth(req),projectId);return ApiResponse.ok(projectStats(projectId)); }
    @GetMapping("/project-dashboard/overview") ApiResponse<Map<String,Object>> projectDashboard(jakarta.servlet.http.HttpServletRequest req,@RequestParam Long projectId){checkProject(auth(req),projectId);return ApiResponse.ok(projectStats(projectId)); }
    @GetMapping("/screen/project/{projectId}") ApiResponse<Map<String,Object>> screen(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long projectId){
        checkProject(auth(req),projectId);
        Project p=require(projects,projectId,"项目不存在");List<Worker> ws=workers.findByProjectId(projectId);List<Device> ds=devices.findByProjectId(projectId);List<AttendanceRecord> records=attendance.findByProjectId(projectId);List<AttendanceRecord> today=records.stream().filter(a->a.getAttendanceTime()!=null&&LocalDate.now().equals(a.getAttendanceTime().toLocalDate())).toList();Map<String,Object> result=new LinkedHashMap<>(projectStats(projectId));
        result.put("project",p);result.put("companyName",companies.findById(p.getCompanyId()).map(Company::getName).orElse("-"));result.put("participantUnitCount",units.findByProjectId(projectId).size());result.put("teamCount",teams.findByProjectId(projectId).size());result.put("onSiteRate",rate(ws.stream().filter(w->"ON_SITE".equals(w.getStatus())).count(),ws.size()));result.put("deviceOfflineCount",ds.stream().filter(d->!"ONLINE".equals(d.getStatus())).count());
        result.put("teamStats",namedWorkerStats(ws,Worker::getTeamId,id->teams.findById(id).map(Team::getTeamName).orElse("未分班组")));result.put("unitStats",namedWorkerStats(ws,Worker::getParticipantUnitId,id->units.findById(id).map(ParticipantUnit::getUnitName).orElse("未分单位")));result.put("workTypeStats",groupCount(ws,Worker::getWorkType));result.put("areaAttendanceStats",groupCount(today,AttendanceRecord::getAreaName));result.put("deviceStatusStats",groupCount(ds,Device::getStatus));result.put("abnormalReasonStats",groupCount(today.stream().filter(a->"DENY".equals(a.getAccessResult())).toList(),AttendanceRecord::getDenyReason));
        List<Map<String,Object>> trend=new ArrayList<>();for(int i=6;i>=0;i--){LocalDate day=LocalDate.now().minusDays(i);List<AttendanceRecord> daily=records.stream().filter(a->a.getAttendanceTime()!=null&&day.equals(a.getAttendanceTime().toLocalDate())).toList();trend.add(Map.of("date",day.toString(),"attendanceCount",daily.stream().map(AttendanceRecord::getWorkerId).filter(Objects::nonNull).distinct().count(),"recordCount",daily.size(),"abnormalCount",daily.stream().filter(a->"DENY".equals(a.getAccessResult())).count()));}result.put("trend",trend);
        Comparator<AttendanceRecord> latest=Comparator.comparing(AttendanceRecord::getAttendanceTime,Comparator.nullsLast(Comparator.naturalOrder())).reversed();result.put("recentAttendance",records.stream().sorted(latest).limit(10).toList());result.put("recentAbnormal",records.stream().filter(a->"DENY".equals(a.getAccessResult())).sorted(latest).limit(6).toList());return ApiResponse.ok(result);
    }

    @GetMapping("/company-dashboard/overview") ApiResponse<Map<String,Object>> companyOverview(jakarta.servlet.http.HttpServletRequest req,@RequestParam Long companyId){
        checkCompany(auth(req),companyId);
        List<Project> ps=projects.findByCompanyId(companyId); List<Map<String,Object>> health=ps.stream().map(this::health).toList();
        return ApiResponse.ok(Map.of("projectCount",ps.size(),"activeProjectCount",ps.stream().filter(p->"在建".equals(p.getStatus())).count(),
                "workerCount",sum(health,"totalWorkers"),"todayAttendance",sum(health,"todayAttendance"),"onSiteCount",sum(health,"onSiteCount"),
                "safetyRate",avg(health,"safetyRate"),"deviceOnlineRate",avg(health,"deviceOnlineRate"),"abnormalCount",sum(health,"abnormalCount"),"reportRate",avg(health,"reportRate")));
    }
