    @PutMapping("/companies/{id}") ApiResponse<Company> editCompany(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody Company v){requireSuperAdmin(req);Company old=require(companies,id,"企业不存在");v.setId(id);v.setTenantId(old.getTenantId());return ApiResponse.ok(companies.save(v));}
    @DeleteMapping("/companies/{id}") ApiResponse<Void> deleteCompany(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){requireSuperAdmin(req);require(companies,id,"企业不存在");if(!projects.findByCompanyId(id).isEmpty())throw new BusinessException("该企业下仍有关联项目，不能删除");if(!platformUsers.findByCompanyIdsContaining(id).isEmpty())throw new BusinessException("该企业仍被管理账号授权，不能删除");companies.deleteById(id);return ApiResponse.ok(null);}

