    @PutMapping("/work-types/{id}") ApiResponse<WorkTypeDictionary> editWorkType(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody WorkTypeDictionary v){requireSuperAdmin(req);WorkTypeDictionary old=require(workTypes,id,"工种不存在");validateWorkType(v,id);v.setId(id);v.setTenantId(old.getTenantId());v.setStatus(or(v.getStatus(),old.getStatus()));v.setSortOrder(or(v.getSortOrder(),0));return ApiResponse.ok(workTypes.save(v));}
    @DeleteMapping("/work-types/{id}") ApiResponse<Void> deleteWorkType(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){requireSuperAdmin(req);WorkTypeDictionary v=require(workTypes,id,"工种不存在");if(workers.findAll().stream().anyMatch(w->Objects.equals(w.getWorkType(),v.getName())))throw new BusinessException("该工种已被劳务人员使用，不能删除");workTypes.delete(v);return ApiResponse.ok(null);}

    @GetMapping("/platform-users")
    ApiResponse<List<Map<String,Object>>> platformUsers(jakarta.servlet.http.HttpServletRequest req,@RequestParam(required=false) Long companyId){
        requireSuperAdmin(req);List<PlatformUser> list=companyId!=null?platformUsers.findByCompanyIdsContaining(companyId):platformUsers.findAll();
        list=list.stream().filter(u->"COMPANY_ADMIN".equals(u.getRole())).toList();
        return ApiResponse.ok(list.stream().map(this::userView).toList());
    }
    @PostMapping("/platform-users")
    ApiResponse<Map<String,Object>> addPlatformUser(jakarta.servlet.http.HttpServletRequest req,@RequestBody PlatformUser v){
        requireSuperAdmin(req);v.setRole("COMPANY_ADMIN");v.setTenantId(defaultTenantId());
        if(platformUsers.findByPhone(v.getPhone()).isPresent())throw new BusinessException("手机号已被其他管理员使用");
        validateCompanyIds(v.getCompanyIds());v.setAllProjectCompanyIds(new LinkedHashSet<>(v.getCompanyIds()));v.setProjectIds(new LinkedHashSet<>());v.setCompanyId(null);v.setUsername(or(v.getUsername(),v.getPhone()));v.setPassword(authService.encode(or(v.getPassword(),"123456")));v.setStatus(or(v.getStatus(),"ACTIVE"));
        return ApiResponse.ok("管理员创建成功",userView(platformUsers.save(v)));
    }
    @PutMapping("/platform-users/{id}")
    ApiResponse<Map<String,Object>> editPlatformUser(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody PlatformUser v){
        requireSuperAdmin(req);
        PlatformUser old=require(platformUsers,id,"管理员不存在");platformUsers.findByPhone(v.getPhone()).filter(x->!Objects.equals(x.getId(),id)).ifPresent(x->{throw new BusinessException("手机号已被其他管理员使用");});
        validateCompanyIds(v.getCompanyIds());old.setName(v.getName());old.setPhone(v.getPhone());old.setUsername(or(v.getUsername(),v.getPhone()));old.setRole("COMPANY_ADMIN");old.setCompanyIds(v.getCompanyIds());old.setAllProjectCompanyIds(new LinkedHashSet<>(v.getCompanyIds()));old.setProjectIds(new LinkedHashSet<>());old.setCompanyId(null);old.setStatus(or(v.getStatus(),old.getStatus()));old.setRemark(v.getRemark());
        return ApiResponse.ok("管理员信息已更新",userView(platformUsers.save(old)));
    }
    @PostMapping("/platform-users/{id}/reset-password")
    ApiResponse<Map<String,String>> resetPassword(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){
        requireSuperAdmin(req);PlatformUser u=require(platformUsers,id,"管理员不存在");String password="BG"+String.format("%06d",new Random().nextInt(1_000_000));u.setPassword(authService.encode(password));platformUsers.save(u);return ApiResponse.ok("密码已重置",Map.of("temporaryPassword",password));
    }
    @PostMapping("/platform-users/{id}/toggle-status")
    ApiResponse<Map<String,Object>> toggleUser(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){
        requireSuperAdmin(req);PlatformUser u=require(platformUsers,id,"管理员不存在");u.setStatus("ACTIVE".equals(u.getStatus())?"DISABLED":"ACTIVE");return ApiResponse.ok(userView(platformUsers.save(u)));
    }
    @DeleteMapping("/platform-users/{id}") ApiResponse<Void> deletePlatformUser(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){requireSuperAdmin(req);platformUsers.deleteById(id);return ApiResponse.ok(null);}

