    @PostMapping("/company-users")
    ApiResponse<Map<String,Object>> addCompanyUser(jakarta.servlet.http.HttpServletRequest req,@RequestBody PlatformUser v){
        Long companyId=singleCompany(v);requireCompanyAdmin(req,companyId);validateUserProjectScope(v,companyId);
        validateCompanyRoleIds(v.getCompanyRoleIds(),companyId);
        if(platformUsers.findByPhone(v.getPhone()).isPresent())throw new BusinessException("手机号已被其他用户使用");
        v.setRole("COMPANY_USER");v.setTenantId(defaultTenantId());v.setUsername(v.getPhone());v.setPassword(authService.encode(or(v.getPassword(),"123456")));v.setStatus(or(v.getStatus(),"ACTIVE"));v.setCompanyId(null);
        return ApiResponse.ok("企业用户创建成功",userView(platformUsers.save(v)));
    }
    @PutMapping("/company-users/{id}")
    ApiResponse<Map<String,Object>> editCompanyUser(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody PlatformUser v){
        Long companyId=singleCompany(v);requireCompanyAdmin(req,companyId);validateUserProjectScope(v,companyId);PlatformUser old=require(platformUsers,id,"企业用户不存在");if(!old.getCompanyIds().contains(companyId))throw new BusinessException("无权编辑其他企业用户");
        if("COMPANY_ADMIN".equals(old.getRole()))throw new BusinessException("企业管理员只能由平台超级管理员维护");
        validateCompanyRoleIds(v.getCompanyRoleIds(),companyId);
        platformUsers.findByPhone(v.getPhone()).filter(x->!Objects.equals(x.getId(),id)).ifPresent(x->{throw new BusinessException("手机号已被其他用户使用");});
        old.setName(v.getName());old.setPhone(v.getPhone());old.setUsername(v.getPhone());old.setStatus(or(v.getStatus(),old.getStatus()));old.setCompanyRoleIds(v.getCompanyRoleIds());
        Set<Long> allProjectCompanies=new LinkedHashSet<>(old.getAllProjectCompanyIds());allProjectCompanies.remove(companyId);if(v.getAllProjectCompanyIds().contains(companyId))allProjectCompanies.add(companyId);old.setAllProjectCompanyIds(allProjectCompanies);
        Set<Long> projectIds=new LinkedHashSet<>(old.getProjectIds());projectIds.removeIf(id2->projects.findById(id2).map(p->Objects.equals(p.getCompanyId(),companyId)).orElse(false));projectIds.addAll(v.getProjectIds());old.setProjectIds(projectIds);
        return ApiResponse.ok("企业用户已更新",userView(platformUsers.save(old)));
    }
    @PostMapping("/company-users/{id}/reset-password") ApiResponse<Map<String,String>> resetCompanyUserPassword(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){PlatformUser u=require(platformUsers,id,"企业用户不存在");if("COMPANY_ADMIN".equals(u.getRole()))throw new BusinessException("企业管理员只能由平台超级管理员维护");requireCompanyAdmin(req,singleCompany(u));String password="BG"+String.format("%06d",new Random().nextInt(1_000_000));u.setPassword(authService.encode(password));platformUsers.save(u);return ApiResponse.ok(Map.of("temporaryPassword",password));}
    @DeleteMapping("/company-users/{id}") ApiResponse<Void> deleteCompanyUser(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){PlatformUser u=require(platformUsers,id,"企业用户不存在");if("COMPANY_ADMIN".equals(u.getRole()))throw new BusinessException("企业管理员只能由平台超级管理员维护");requireCompanyAdmin(req,singleCompany(u));platformUsers.deleteById(id);return ApiResponse.ok(null);}

