    @DeleteMapping("/projects/{id}") ApiResponse<Void> deleteProject(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){Project p=require(projects,id,"项目不存在");requireCompanyAdmin(req,p.getCompanyId());if(!workers.findByProjectId(id).isEmpty()||!units.findByProjectId(id).isEmpty()||!areas.findByProjectId(id).isEmpty()||!teams.findByProjectId(id).isEmpty()||!devices.findByProjectId(id).isEmpty())throw new BusinessException("该项目已有业务数据，不能删除");projects.deleteById(id);return ApiResponse.ok(null);}

