    @PutMapping("/company-roles/{id}") ApiResponse<ScopeRole> editCompanyRole(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody ScopeRole v){ScopeRole old=require(scopeRoles,id,"角色不存在");requireCompanyAdmin(req,old.getScopeId());return ApiResponse.ok(updateRole(old,v));}
    @DeleteMapping("/company-roles/{id}") ApiResponse<Void> deleteCompanyRole(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){ScopeRole role=require(scopeRoles,id,"角色不存在");requireCompanyAdmin(req,role.getScopeId());deleteRole(role);return ApiResponse.ok(null);}

