    @PutMapping("/project-roles/{id}") ApiResponse<ScopeRole> editProjectRole(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody ScopeRole v){ScopeRole old=require(scopeRoles,id,"角色不存在");requireProjectManager(req,old.getScopeId());return ApiResponse.ok(updateRole(old,v));}
