    @GetMapping("/project-users") ApiResponse<List<Map<String,Object>>> projectUsers(jakarta.servlet.http.HttpServletRequest req,@RequestParam Long projectId){requireProjectManager(req,projectId);return ApiResponse.ok(platformUsers.findAll().stream().filter(u->u.getProjectIds().contains(projectId)&&"COMPANY_USER".equals(u.getRole())).map(this::userView).toList());}
    @PostMapping("/project-users") ApiResponse<Map<String,Object>> addProjectUser(jakarta.servlet.http.HttpServletRequest req,@RequestBody PlatformUser v){Long projectId=singleProject(v);Project project=require(projects,projectId,"项目不存在");requireProjectManager(req,projectId);validateProjectRoleIds(v.getProjectRoleIds(),projectId);if(platformUsers.findByPhone(v.getPhone()).isPresent())throw new BusinessException("手机号已被其他用户使用");v.setRole("COMPANY_USER");v.setCompanyIds(new LinkedHashSet<>(Set.of(project.getCompanyId())));v.setAllProjectCompanyIds(new LinkedHashSet<>());v.setTenantId(defaultTenantId());v.setUsername(v.getPhone());v.setPassword(authService.encode(or(v.getPassword(),"123456")));v.setStatus(or(v.getStatus(),"ACTIVE"));return ApiResponse.ok(userView(platformUsers.save(v)));}
    @PutMapping("/project-users/{id}") ApiResponse<Map<String,Object>> editProjectUser(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody PlatformUser v){Long projectId=singleProject(v);requireProjectManager(req,projectId);validateProjectRoleIds(v.getProjectRoleIds(),projectId);PlatformUser old=require(platformUsers,id,"项目用户不存在");old.setName(v.getName());old.setPhone(v.getPhone());old.setUsername(v.getPhone());old.setStatus(or(v.getStatus(),old.getStatus()));Set<Long> projectIds=new LinkedHashSet<>(old.getProjectIds());projectIds.add(projectId);old.setProjectIds(projectIds);Set<Long> roleIds=new LinkedHashSet<>(old.getProjectRoleIds());roleIds.removeIf(roleId->scopeRoles.findById(roleId).map(r->"PROJECT".equals(r.getScopeType())&&Objects.equals(r.getScopeId(),projectId)).orElse(false));roleIds.addAll(v.getProjectRoleIds());old.setProjectRoleIds(roleIds);return ApiResponse.ok(userView(platformUsers.save(old)));}
    @DeleteMapping("/project-users/{id}") ApiResponse<Void> deleteProjectUser(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestParam Long projectId){requireProjectManager(req,projectId);PlatformUser user=require(platformUsers,id,"项目用户不存在");user.getProjectIds().remove(projectId);user.getProjectRoleIds().removeIf(roleId->scopeRoles.findById(roleId).map(r->Objects.equals(r.getScopeId(),projectId)&&"PROJECT".equals(r.getScopeType())).orElse(false));platformUsers.save(user);return ApiResponse.ok(null);}

    @GetMapping("/participant-units") ApiResponse<List<ParticipantUnit>> units(jakarta.servlet.http.HttpServletRequest req,@RequestParam(required=false) Long projectId){AuthScope a=auth(req);if(projectId!=null)checkProject(a,projectId);return ApiResponse.ok(projectId==null?units.findAll().stream().filter(x->allowedProject(a,x.getProjectId())).toList():units.findByProjectId(projectId));}
    @PostMapping("/participant-units") ApiResponse<ParticipantUnit> addUnit(jakarta.servlet.http.HttpServletRequest req,@RequestBody ParticipantUnit v){checkProject(auth(req),v.getProjectId());v.setTenantId(defaultTenantId());v.setStatus(or(v.getStatus(),"ACTIVE"));return ApiResponse.ok(units.save(v));}
    @PutMapping("/participant-units/{id}") ApiResponse<ParticipantUnit> editUnit(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody ParticipantUnit v){ParticipantUnit old=require(units,id,"参建单位不存在");checkProject(auth(req),old.getProjectId());v.setId(id);v.setProjectId(old.getProjectId());v.setTenantId(old.getTenantId());return ApiResponse.ok(units.save(v));}
    @DeleteMapping("/participant-units/{id}") ApiResponse<Void> deleteUnit(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){ParticipantUnit unit=require(units,id,"参建单位不存在");checkProject(auth(req),unit.getProjectId());if(teams.findByProjectId(unit.getProjectId()).stream().anyMatch(t->Objects.equals(t.getParticipantUnitId(),id))||workers.findByProjectId(unit.getProjectId()).stream().anyMatch(w->Objects.equals(w.getParticipantUnitId(),id)))throw new BusinessException("该参建单位已关联班组或人员，不能删除");units.deleteById(id);return ApiResponse.ok(null);}

    @GetMapping("/project-areas") ApiResponse<List<ProjectArea>> areas(jakarta.servlet.http.HttpServletRequest req,@RequestParam(required=false) Long projectId){AuthScope a=auth(req);if(projectId!=null)checkProject(a,projectId);return ApiResponse.ok(projectId==null?areas.findAll().stream().filter(x->allowedProject(a,x.getProjectId())).toList():areas.findByProjectId(projectId));}
    @PostMapping("/project-areas") ApiResponse<ProjectArea> addArea(jakarta.servlet.http.HttpServletRequest req,@RequestBody ProjectArea v){checkProject(auth(req),v.getProjectId());v.setTenantId(defaultTenantId());v.setStatus(or(v.getStatus(),"ACTIVE"));return ApiResponse.ok(areas.save(v));}
    @PutMapping("/project-areas/{id}") ApiResponse<ProjectArea> editArea(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody ProjectArea v){ProjectArea old=require(areas,id,"区域不存在");checkProject(auth(req),old.getProjectId());v.setId(id);v.setProjectId(old.getProjectId());v.setTenantId(old.getTenantId());return ApiResponse.ok(areas.save(v));}
    @DeleteMapping("/project-areas/{id}") ApiResponse<Void> deleteArea(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){ProjectArea area=require(areas,id,"区域不存在");checkProject(auth(req),area.getProjectId());if(!devices.findByAreaId(id).isEmpty()||permissions.findAll().stream().anyMatch(p->Objects.equals(p.getAreaId(),id)))throw new BusinessException("该区域已关联设备或人员权限，不能删除");areas.deleteById(id);return ApiResponse.ok(null);}

    @GetMapping("/teams") ApiResponse<List<Team>> teams(jakarta.servlet.http.HttpServletRequest req,@RequestParam(required=false) Long projectId){AuthScope a=auth(req);if(projectId!=null)checkProject(a,projectId);return ApiResponse.ok(projectId==null?teams.findAll().stream().filter(x->allowedProject(a,x.getProjectId())).toList():teams.findByProjectId(projectId));}
    @PostMapping("/teams") ApiResponse<Team> addTeam(jakarta.servlet.http.HttpServletRequest req,@RequestBody Team v){checkProject(auth(req),v.getProjectId());validateTeamUnit(v);v.setTenantId(defaultTenantId());v.setStatus(or(v.getStatus(),"ACTIVE"));return ApiResponse.ok(teams.save(v));}
    @PutMapping("/teams/{id}") ApiResponse<Team> editTeam(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody Team v){Team old=require(teams,id,"班组不存在");checkProject(auth(req),old.getProjectId());v.setId(id);v.setProjectId(old.getProjectId());v.setTenantId(old.getTenantId());validateTeamUnit(v);return ApiResponse.ok(teams.save(v));}
    @DeleteMapping("/teams/{id}") ApiResponse<Void> deleteTeam(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){Team team=require(teams,id,"班组不存在");checkProject(auth(req),team.getProjectId());if(workers.findByProjectId(team.getProjectId()).stream().anyMatch(w->Objects.equals(w.getTeamId(),id)))throw new BusinessException("该班组已关联人员，不能删除");teams.deleteById(id);return ApiResponse.ok(null);}

    @GetMapping("/workers") ApiResponse<List<WorkerListItem>> workers(jakarta.servlet.http.HttpServletRequest req,@RequestParam(required=false) Long projectId,@RequestParam(required=false) String status){AuthScope a=auth(req);if(projectId!=null)checkProject(a,projectId);List<Worker> list=projectId==null?workers.findAll().stream().filter(x->allowedProject(a,x.getProjectId())).toList():workers.findByProjectId(projectId);return ApiResponse.ok((status==null?list:list.stream().filter(w->status.equals(w.getStatus())).toList()).stream().map(WorkerListItem::from).toList());}
    @PostMapping("/workers") ApiResponse<Worker> addWorker(jakarta.servlet.http.HttpServletRequest req,@RequestBody Worker v){checkProject(auth(req),v.getProjectId());validateWorker(v,null);prepareTeamLeader(v,null);v.setPersonCode(nextWorkerCode(v.getProjectId()));v.setQrToken(UUID.randomUUID().toString().replace("-",""));v.setWorkerType(or(v.getWorkerType(),"劳务工人"));v.setStatus(or(v.getStatus(),"WAIT_ENTRY"));v.setSafetyEducationStatus("FAILED");v.setAccessStatus("ACCESS_DISABLED");v.setDeviceSyncStatus("NOT_SYNCED");v.setRealNameReportStatus("NOT_SUBMITTED");return ApiResponse.ok(workers.save(v));}
    @PutMapping("/workers/{id}") ApiResponse<Worker> editWorker(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody Worker v){Worker old=requireWorker(id);checkProject(auth(req),old.getProjectId());v.setId(id);v.setProjectId(old.getProjectId());validateWorker(v,id);prepareTeamLeader(v,old);v.setPersonCode(old.getPersonCode());v.setQrToken(old.getQrToken());v.setSafetyEducationStatus(old.getSafetyEducationStatus());v.setAccessStatus(old.getAccessStatus());v.setDeviceSyncStatus(old.getDeviceSyncStatus());v.setLastAttendanceTime(old.getLastAttendanceTime());v.setLastSyncTime(old.getLastSyncTime());v.setWorkerType(or(v.getWorkerType(),old.getWorkerType()));v.setStatus(or(v.getStatus(),old.getStatus()));return ApiResponse.ok(workers.save(v));}
    @Transactional
    @DeleteMapping("/workers/{id}") ApiResponse<Void> deleteWorker(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){
        Worker w=requireWorker(id);checkProject(auth(req),w.getProjectId());
        syncLogs.deleteByWorkerId(id);attendance.deleteByWorkerId(id);permissions.deleteByWorkerId(id);exams.deleteByWorkerId(id);ledgers.deleteByWorkerId(id);
        workers.delete(w);return ApiResponse.ok(null);
    }
    @GetMapping("/workers/{id}") ApiResponse<Worker> worker(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){Worker w=requireWorker(id);checkProject(auth(req),w.getProjectId());return ApiResponse.ok(w);}
    @GetMapping("/workers/{id}/detail") ApiResponse<Map<String,Object>> workerDetail(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){Worker w=requireWorker(id);checkProject(auth(req),w.getProjectId());Map<String,Object> m=new LinkedHashMap<>();m.put("worker",w);m.put("project",projects.findById(w.getProjectId()).orElse(null));m.put("participantUnit",w.getParticipantUnitId()==null?null:units.findById(w.getParticipantUnitId()).orElse(null));m.put("team",w.getTeamId()==null?null:teams.findById(w.getTeamId()).orElse(null));m.put("permissions",permissions.findByWorkerId(id));m.put("areas",areas.findByProjectId(w.getProjectId()));m.put("educationLedger",ledgers.findByWorkerId(id));m.put("exams",exams.findByProjectId(w.getProjectId()).stream().filter(x->Objects.equals(x.getWorkerId(),id)).toList());m.put("attendance",attendance.findByProjectId(w.getProjectId()).stream().filter(x->Objects.equals(x.getWorkerId(),id)).toList());m.put("syncLogs",syncLogs.findByProjectId(w.getProjectId()).stream().filter(x->Objects.equals(x.getWorkerId(),id)).toList());m.put("reportLogs",reportLogs.findAll().stream().filter(x->"WORKER".equals(x.getBusinessType())&&Objects.equals(x.getBusinessId(),id)).toList());return ApiResponse.ok(m);}
    @PostMapping({"/workers/{id}/entry","/workers/{id}/enter"}) ApiResponse<Worker> enter(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){checkWorker(req,id);return updateWorker(id,w->{w.setStatus("ON_SITE");w.setEntryDate(LocalDate.now().toString());w.setExitDate(null);});}
    @PostMapping("/workers/{id}/exit") ApiResponse<Worker> exit(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){checkWorker(req,id);return updateWorker(id,w->{w.setStatus("LEFT_SITE");w.setExitDate(LocalDate.now().toString());w.setAccessStatus("ACCESS_DISABLED");});}
    @PostMapping("/workers/{id}/blacklist") ApiResponse<Worker> blacklist(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){checkWorker(req,id);return updateWorker(id,w->{w.setStatus("BLACKLIST");w.setAccessStatus("ACCESS_DISABLED");});}
    @PostMapping("/workers/{id}/remove-blacklist") ApiResponse<Worker> removeBlacklist(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){checkWorker(req,id);return updateWorker(id,w->{w.setStatus("WAIT_ENTRY");w.setAccessStatus("ACCESS_DISABLED");w.setDeviceSyncStatus("NOT_SYNCED");});}
    @PostMapping("/workers/{id}/team-leader") ApiResponse<Worker> setTeamLeader(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody Map<String,Object> body){Worker w=requireWorker(id);requireProjectManager(req,w.getProjectId());boolean enabled=Boolean.parseBoolean(String.valueOf(body.getOrDefault("enabled",false)));w.setTeamLeader(enabled);w.setTeamLeaderPassword(enabled?authService.encode(or(text(body.get("password")),"123456")):null);if(enabled&&w.getTeamId()==null)throw new BusinessException("班组长必须归属具体班组");return ApiResponse.ok(workers.save(w));}
    @PostMapping("/workers/{id}/submit-realname") ApiResponse<ReportLog> submitWorkerRealName(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){Worker w=requireWorker(id);checkProject(auth(req),w.getProjectId());ReportLog log=doReport("WORKER",id);w.setRealNameReportStatus(log.getStatus());w.setRealNameReportedAt(log.getSubmittedAt());w.setRealNameReportResult("SUCCESS".equals(log.getStatus())?"上报成功":log.getErrorMessage());workers.save(w);return ApiResponse.ok(log);}
    @PostMapping("/workers/{id}/generate-qrcode") ApiResponse<Map<String,String>> qr(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){Worker w=requireWorker(id);checkProject(auth(req),w.getProjectId());if(w.getQrToken()==null)w.setQrToken(UUID.randomUUID().toString().replace("-",""));workers.save(w);return ApiResponse.ok(Map.of("qrToken",w.getQrToken(),"url",publicFrontendUrl()+"/mobile/worker/"+w.getQrToken()));}
