    @PostMapping("/workers/import-preview") ApiResponse<Map<String,Object>> importPreview(jakarta.servlet.http.HttpServletRequest req,@RequestBody Map<String,Object> b){Long projectId=longValue(b.get("projectId"),"请选择项目");checkProject(auth(req),projectId);List<Map<String,Object>> result=validateImportRows(projectId,rowsOf(b));long valid=result.stream().filter(r->Boolean.TRUE.equals(r.get("valid"))).count();return ApiResponse.ok(Map.of("rows",result,"validCount",valid,"errorCount",result.size()-valid));}
    @Transactional
    @PostMapping("/workers/import-confirm") ApiResponse<Map<String,Object>> importConfirm(jakarta.servlet.http.HttpServletRequest req,@RequestBody Map<String,Object> b){Long projectId=longValue(b.get("projectId"),"请选择项目");checkProject(auth(req),projectId);List<Map<String,Object>> checked=validateImportRows(projectId,rowsOf(b));if(checked.stream().anyMatch(r->!Boolean.TRUE.equals(r.get("valid"))))throw new BusinessException("导入数据仍有校验错误，请修正后重新预览");int count=0;for(Map<String,Object> row:checked){Worker w=new Worker();w.setProjectId(projectId);w.setName(text(row.get("name")));w.setIdCardNo(text(row.get("idCardNo")));w.setPhone(text(row.get("phone")));w.setWorkType(text(row.get("workType")));w.setParticipantUnitId(nullableLong(row.get("participantUnitId")));w.setTeamId(nullableLong(row.get("teamId")));Worker saved=addWorker(req,w).data();for(Long areaId:longList(row.get("areaIds")))permissions.save(WorkerAreaPermission.builder().workerId(saved.getId()).projectId(projectId).areaId(areaId).permissionStatus("ACTIVE").deviceSyncStatus("PENDING_SYNC").build());count++;}return ApiResponse.ok(Map.of("success",true,"count",count));}
