    @GetMapping("/education/courses") ApiResponse<List<EducationCourse>> courses(jakarta.servlet.http.HttpServletRequest req,@RequestParam Long projectId){checkProject(auth(req),projectId);migrateQuestionBank(projectId);return ApiResponse.ok(courses.findByProjectId(projectId));}
    @PostMapping("/education/courses") ApiResponse<EducationCourse> addCourse(jakarta.servlet.http.HttpServletRequest req,@RequestBody EducationCourse v){checkProject(auth(req),v.getProjectId());validateCourse(v);validateCourseQuestions(v);v.setStatus(or(v.getStatus(),"ACTIVE"));return ApiResponse.ok(courses.save(v));}
    @PutMapping("/education/courses/{id}") ApiResponse<EducationCourse> editCourse(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody EducationCourse v){EducationCourse old=require(courses,id,"课程不存在");checkProject(auth(req),old.getProjectId());validateCourse(v);v.setId(id);v.setProjectId(old.getProjectId());validateCourseQuestions(v);v.setStatus(or(v.getStatus(),old.getStatus()));return ApiResponse.ok(courses.save(v));}
    @DeleteMapping("/education/courses/{id}") ApiResponse<Void> deleteCourse(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){EducationCourse c=require(courses,id,"课程不存在");checkProject(auth(req),c.getProjectId());if(exams.findByProjectId(c.getProjectId()).stream().anyMatch(e->Objects.equals(e.getCourseId(),id)))throw new BusinessException("课程已有考试记录，不能删除");courses.deleteById(id);return ApiResponse.ok(null);}
    @GetMapping("/education/questions") ApiResponse<List<EducationQuestion>> questions(jakarta.servlet.http.HttpServletRequest req,@RequestParam(required=false) Long projectId,@RequestParam(required=false) Long courseId){if(projectId==null){EducationCourse c=require(courses,courseId,"课程不存在");projectId=c.getProjectId();checkProject(auth(req),projectId);migrateQuestionBank(projectId);return ApiResponse.ok(courseQuestions(c));}checkProject(auth(req),projectId);migrateQuestionBank(projectId);return ApiResponse.ok(questions.findByProjectId(projectId));}
    @PostMapping("/education/questions") ApiResponse<EducationQuestion> addQuestion(jakarta.servlet.http.HttpServletRequest req,@RequestBody EducationQuestion v){checkProject(auth(req),v.getProjectId());validateQuestion(v);v.setCourseId(null);v.setStatus(or(v.getStatus(),"ACTIVE"));return ApiResponse.ok(questions.save(v));}
    @PutMapping("/education/questions/{id}") ApiResponse<EducationQuestion> editQuestion(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id,@RequestBody EducationQuestion v){EducationQuestion old=require(questions,id,"考题不存在");Long projectId=questionProjectId(old);checkProject(auth(req),projectId);validateQuestion(v);v.setId(id);v.setProjectId(projectId);v.setCourseId(null);v.setStatus(or(v.getStatus(),old.getStatus()));return ApiResponse.ok(questions.save(v));}
    @DeleteMapping("/education/questions/{id}") ApiResponse<Void> deleteQuestion(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){EducationQuestion q=require(questions,id,"考题不存在");checkProject(auth(req),questionProjectId(q));if(courses.findAll().stream().anyMatch(c->c.getQuestionIds()!=null&&c.getQuestionIds().contains(id)))throw new BusinessException("考题已被课程使用，请先从课程中移除");questions.deleteById(id);return ApiResponse.ok(null);}
    @GetMapping("/education/exams") ApiResponse<List<EducationExam>> exams(jakarta.servlet.http.HttpServletRequest req,@RequestParam Long projectId){checkProject(auth(req),projectId);return ApiResponse.ok(exams.findByProjectId(projectId));}
    @PostMapping({"/education/exams/mock-pass","/education/exams/mock-fail"}) ApiResponse<EducationExam> mockExam(@RequestBody Map<String,Object> b,jakarta.servlet.http.HttpServletRequest req){
        boolean passed=req.getRequestURI().endsWith("mock-pass"); Worker w=requireWorker(longValue(b.get("workerId"),"请选择人员")); EducationCourse c=require(courses,longValue(b.get("courseId"),"请选择课程"),"课程不存在");checkProject(auth(req),w.getProjectId());if(!Objects.equals(w.getProjectId(),c.getProjectId()))throw new BusinessException("人员与课程不属于同一项目");
        EducationExam e=exams.save(EducationExam.builder().workerId(w.getId()).workerName(w.getName()).projectId(w.getProjectId()).courseId(c.getId()).courseName(c.getName()).startTime(LocalDateTime.now().minusMinutes(20)).finishTime(LocalDateTime.now()).score(passed?95:55).passed(passed).validStartDate(LocalDate.now().toString()).validEndDate(LocalDate.now().plusDays(or(c.getValidDays(),365)).toString()).build());
        if(passed) createLedger(w,c,"线上考试",95); refreshEducation(w); return ApiResponse.ok(e);
    }
    @GetMapping("/education/ledger") ApiResponse<List<EducationLedger>> ledger(jakarta.servlet.http.HttpServletRequest req,@RequestParam Long projectId){checkProject(auth(req),projectId);return ApiResponse.ok(ledgers.findByProjectId(projectId));}
    @PostMapping("/education/ledger/offline") ApiResponse<EducationLedger> offline(jakarta.servlet.http.HttpServletRequest req,@RequestBody EducationLedger v){Worker w=requireWorker(v.getWorkerId());checkProject(auth(req),w.getProjectId());v.setProjectId(w.getProjectId());v.setWorkerName(w.getName());v.setParticipantUnitId(w.getParticipantUnitId());v.setTeamId(w.getTeamId());v.setWorkType(w.getWorkType());v.setEducationMethod("线下教育");v.setEducationDate(or(v.getEducationDate(),LocalDate.now().toString()));v.setPassed(v.getPassed()==null?true:v.getPassed());v.setValidStartDate(or(v.getValidStartDate(),LocalDate.now().toString()));v.setValidEndDate(or(v.getValidEndDate(),LocalDate.now().plusYears(1).toString()));EducationLedger x=ledgers.save(v);refreshEducation(w);return ApiResponse.ok(x);}
    @PostMapping("/education/ledger/{id}/mark-pass") ApiResponse<EducationLedger> ledgerPass(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){EducationLedger l=require(ledgers,id,"台账不存在");checkProject(auth(req),l.getProjectId());return markLedger(id,true);}
    @PostMapping("/education/ledger/{id}/mark-fail") ApiResponse<EducationLedger> ledgerFail(jakarta.servlet.http.HttpServletRequest req,@PathVariable Long id){EducationLedger l=require(ledgers,id,"台账不存在");checkProject(auth(req),l.getProjectId());return markLedger(id,false);}

