    @PostMapping("/education/training-tasks") ApiResponse<Map<String,Object>> addTrainingTask(jakarta.servlet.http.HttpServletRequest req,@RequestBody TrainingTask v){EducationCourse c=require(courses,v.getCourseId(),"课程不存在");checkProject(auth(req),c.getProjectId());v.setProjectId(c.getProjectId());validateTrainingTargets(v);v.setTaskToken(UUID.randomUUID().toString().replace("-",""));v.setStatus(or(v.getStatus(),"ACTIVE"));return ApiResponse.ok(trainingTaskView(trainingTasks.save(v)));}
