    @GetMapping("/device-open-api/logs") ApiResponse<List<DeviceOpenApiLog>> deviceOpenLogs(jakarta.servlet.http.HttpServletRequest req,@RequestParam(required=false) Long projectId,@RequestParam(required=false) String deviceNo,@RequestParam(required=false) String interfaceName,@RequestParam(required=false) Boolean success){AuthScope a=auth(req);if(projectId!=null)checkProject(a,projectId);Map<String,Device> deviceMap=devices.findAll().stream().filter(d->d.getDeviceNo()!=null).collect(java.util.stream.Collectors.toMap(Device::getDeviceNo,d->d,(x,y)->x));Set<String> projectDeviceNos=projectId==null?Set.of():devices.findByProjectId(projectId).stream().map(Device::getDeviceNo).collect(java.util.stream.Collectors.toSet());return ApiResponse.ok(openApiLogs.findAll().stream().filter(l->{if(projectId!=null)return projectDeviceNos.contains(l.getDeviceNo());Device d=deviceMap.get(l.getDeviceNo());return d==null?a.superAdmin():allowedProject(a,d.getProjectId());}).filter(l->text(deviceNo).isBlank()||text(deviceNo).equals(l.getDeviceNo())).filter(l->text(interfaceName).isBlank()||text(interfaceName).equals(l.getInterfaceName())).filter(l->success==null||Objects.equals(success,l.getSuccess())).sorted(Comparator.comparing(DeviceOpenApiLog::getCreatedAt,Comparator.nullsLast(Comparator.naturalOrder())).reversed()).limit(500).toList());}
