    @Transactional
    @PostMapping("/worker-area-permissions/save") ApiResponse<List<WorkerAreaPermission>> savePermission(jakarta.servlet.http.HttpServletRequest req,@RequestBody Map<String,Object> b){Long workerId=longValue(b.get("workerId"),"请选择人员");Worker worker=requireWorker(workerId);checkProject(auth(req),worker.getProjectId());List<Long> areaIds=longList(b.get("areaIds"));for(Long areaId:areaIds)if(!Objects.equals(require(areas,areaId,"区域不存在").getProjectId(),worker.getProjectId()))throw new BusinessException("包含其他项目区域");permissions.deleteByWorkerId(workerId);List<WorkerAreaPermission> saved=new ArrayList<>();for(Long areaId:areaIds)saved.add(permissions.save(WorkerAreaPermission.builder().workerId(workerId).projectId(worker.getProjectId()).areaId(areaId).permissionStatus("ACTIVE").deviceSyncStatus("PENDING_SYNC").validStartTime(parseDateTime(b.get("validStartTime"))).validEndTime(parseDateTime(b.get("validEndTime"))).build()));worker.setDeviceSyncStatus("PENDING_SYNC");worker.setAccessStatus("ACCESS_DISABLED");workers.save(worker);return ApiResponse.ok(saved);}
