    @GetMapping("/attendance/stat") ApiResponse<Map<String,Object>> attendanceStat(jakarta.servlet.http.HttpServletRequest req,@RequestParam Long projectId){checkProject(auth(req),projectId);List<AttendanceRecord> records=attendance.findByProjectId(projectId);List<AttendanceRecord> today=records.stream().filter(a->a.getAttendanceTime()!=null&&a.getAttendanceTime().toLocalDate().equals(LocalDate.now())).toList();Map<String,Object> result=new LinkedHashMap<>(projectStats(projectId));result.put("inCount",today.stream().filter(a->"IN".equals(a.getDirection())).count());result.put("outCount",today.stream().filter(a->"OUT".equals(a.getDirection())).count());result.put("allowCount",today.stream().filter(a->"ALLOW".equals(a.getAccessResult())).count());result.put("areaStats",groupCount(today,AttendanceRecord::getAreaName));result.put("abnormalReasonStats",groupCount(today.stream().filter(a->"DENY".equals(a.getAccessResult())).toList(),AttendanceRecord::getDenyReason));List<Map<String,Object>> trend=new ArrayList<>();for(int i=6;i>=0;i--){LocalDate day=LocalDate.now().minusDays(i);List<AttendanceRecord> daily=records.stream().filter(a->a.getAttendanceTime()!=null&&day.equals(a.getAttendanceTime().toLocalDate())).toList();trend.add(Map.of("date",day.toString(),"attendanceCount",daily.stream().map(AttendanceRecord::getWorkerId).filter(Objects::nonNull).distinct().count(),"recordCount",daily.size(),"abnormalCount",daily.stream().filter(a->"DENY".equals(a.getAccessResult())).count()));}result.put("trend",trend);return ApiResponse.ok(result);}
    @GetMapping("/attendance/daily-detail") ApiResponse<Map<String,Object>> attendanceDailyDetail(jakarta.servlet.http.HttpServletRequest req,@RequestParam Long projectId,@RequestParam(required=false) String date){
        checkProject(auth(req),projectId);LocalDate day=date==null||date.isBlank()?LocalDate.now():LocalDate.parse(date);List<Worker> projectWorkers=workers.findByProjectId(projectId);List<AttendanceRecord> daily=attendance.findByProjectId(projectId).stream().filter(a->a.getAttendanceTime()!=null&&day.equals(a.getAttendanceTime().toLocalDate())).sorted(Comparator.comparing(AttendanceRecord::getAttendanceTime)).toList();
        Map<Long,List<AttendanceRecord>> byWorker=daily.stream().filter(a->a.getWorkerId()!=null).collect(java.util.stream.Collectors.groupingBy(AttendanceRecord::getWorkerId,LinkedHashMap::new,java.util.stream.Collectors.toList()));List<Map<String,Object>> details=new ArrayList<>();
        for(Worker worker:projectWorkers){List<AttendanceRecord> records=byWorker.getOrDefault(worker.getId(),List.of());List<Map<String,Object>> shifts=dailyShifts(records);long seconds=shifts.stream().mapToLong(s->((Number)s.get("seconds")).longValue()).sum();boolean denied=records.stream().anyMatch(a->"DENY".equals(a.getAccessResult()));boolean missing=shifts.stream().anyMatch(s->Boolean.TRUE.equals(s.get("missing")));String result=records.isEmpty()?"ABSENT":denied?"ABNORMAL":missing?"MISSING":"NORMAL";Map<String,Object> row=new LinkedHashMap<>();
            row.put("workerId",worker.getId());row.put("personCode",worker.getPersonCode());row.put("workerName",worker.getName());row.put("workType",worker.getWorkType());row.put("teamName",worker.getTeamId()==null?"未分班组":teams.findById(worker.getTeamId()).map(Team::getTeamName).orElse("未分班组"));row.put("unitName",worker.getParticipantUnitId()==null?"未分单位":units.findById(worker.getParticipantUnitId()).map(ParticipantUnit::getUnitName).orElse("未分单位"));row.put("shifts",shifts);row.put("totalSeconds",seconds);row.put("totalDuration",durationText(seconds));row.put("result",result);row.put("recordCount",records.size());details.add(row);
        }
        Map<String,Object> summary=new LinkedHashMap<>();summary.put("date",day.toString());summary.put("workerCount",projectWorkers.size());summary.put("attendanceCount",details.stream().filter(x->!"ABSENT".equals(x.get("result"))).count());summary.put("normalCount",details.stream().filter(x->"NORMAL".equals(x.get("result"))).count());summary.put("missingCount",details.stream().filter(x->"MISSING".equals(x.get("result"))).count());summary.put("abnormalCount",details.stream().filter(x->"ABNORMAL".equals(x.get("result"))).count());summary.put("absentCount",details.stream().filter(x->"ABSENT".equals(x.get("result"))).count());summary.put("rows",details);return ApiResponse.ok(summary);
    }
    @PostMapping("/attendance/manual") ApiResponse<AttendanceRecord> manual(jakarta.servlet.http.HttpServletRequest req,@RequestBody AttendanceRecord v){checkProject(auth(req),v.getProjectId());return ApiResponse.ok(attendance.save(v));}
    @PostMapping("/attendance/mock-generate") ApiResponse<List<AttendanceRecord>> mockAttendance(jakarta.servlet.http.HttpServletRequest req,@RequestBody Map<String,Object> b){
        Long projectId=Long.valueOf(String.valueOf(b.get("projectId")));int count=Integer.parseInt(String.valueOf(b.getOrDefault("count",10)));List<Worker> ws=workers.findByProjectId(projectId);List<Device> ds=devices.findByProjectId(projectId);if(ws.isEmpty()||ds.isEmpty())throw new BusinessException("项目暂无人员或设备");
        checkProject(auth(req),projectId);
        List<AttendanceRecord> result=new ArrayList<>();for(int i=0;i<count;i++){Worker w=ws.get(i%ws.size());Device d=ds.get(i%ds.size());result.add(accessService.pushAttendance(new AttendancePushRequest(d.getDeviceNo(),w.getPersonCode(),w.getIdCardNo(),w.getName(),LocalDateTime.now().minusMinutes(i),i%2==0?"IN":"OUT","MOCK",90d)));}return ApiResponse.ok(result);
    }
